def nCr(n, r):
    return int(factorial(n) / (factorial(r) * factorial(n - r)))


def factorial(n):
    if n == 0:
        return 1
    else:
        return n * factorial(n - 1)


def main():
    n, m = map(int, input().split())
    ans = 0
    for i in range(1, n + 1):
        ans += nCr(n, i) * pow(m - 1, n - i, 1000000007)
    print(ans % 1000000007)


if __name__ == '__main__':
    main()
